@dataclass
class ToolResult:
    """Result from tool execution"""
    success: bool
    output: str
    error: Optional[str] = None
    data: Optional[Dict] = None

class BaseTool:
    """Base class for all tools"""
    
    def __init__(self, config: ToolsConfig):
        self.config = config
        self.working_dir = Path.cwd().resolve()
    
    def _validate_path(self, file_path: str) -> bool:
        """Validate that the path is within the current working directory"""
        try:
            # Convert to absolute path and resolve
            abs_path = Path(file_path).resolve()
            
            # Check if the path is within the working directory
            try:
                abs_path.relative_to(self.working_dir)
                return True
            except ValueError:
                return False
        except Exception:
            return False
    
    def _safe_path(self, file_path: str) -> Optional[Path]:
        """Get a safe path object if the path is valid"""
        if not self._validate_path(file_path):
            return None
        return Path(file_path).resolve()
    
    async def execute(self, **kwargs) -> ToolResult:
        """Execute the tool with given parameters"""
        raise NotImplementedError

class FileReadTool(BaseTool):
    """Tool for reading files"""
    
    async def execute(self, file_path: str, start_line: Optional[int] = None, 
                     end_line: Optional[int] = None) -> ToolResult:
        try:
            # Validate path is within working directory
            safe_path = self._safe_path(file_path)
            if safe_path is None:
                return ToolResult(
                    success=False, 
                    output="",
                    error=f"Access denied: {file_path} is outside the working directory"
                )
            
            if not safe_path.exists():
                return ToolResult(success=False, error=f"File not found: {file_path}")
            
            content = safe_path.read_text(encoding='utf-8')
            
            if start_line is not None or end_line is not None:
                lines = content.split('\n')
                start = (start_line - 1) if start_line else 0
                end = end_line if end_line else len(lines)
                content = '\n'.join(lines[start:end])
            
            return ToolResult(
                success=True,
                output=content,
                data={"file_path": file_path, "size": len(content)}
            )
            
        except Exception as e:
            return ToolResult(success=False, error=str(e))

class FileWriteTool(BaseTool):
    """Tool for writing files"""
    
    async def execute(self, file_path: str, content: str,
                     create_dirs: bool = True) -> ToolResult:
        try:
            # Validate path is within working directory
            safe_path = self._safe_path(file_path)
            if safe_path is None:
                return ToolResult(
                    success=False,
                    output="",
                    error=f"Access denied: {file_path} is outside the working directory"
                )

            # Check if file exists (overwrite operation needs confirmation)
            file_exists = safe_path.exists()
            if file_exists:
                # Request confirmation for overwrite operation
                operation_info = OperationInfo(
                    operation_name="Overwrite File",
                    description=f"Overwrite existing file: {file_path}",
                    risk_level=RiskLevel.MEDIUM,
                    affected_items=[file_path],
                    context_data={"file_size": len(content)}
                )
                if not confirm_operation(operation_info):
                    return ToolResult(
                        success=False,
                        output="",
                        error="Operation cancelled by user - file overwrite not confirmed"
                    )

            if create_dirs:
                # Also validate that the parent directory would be within working directory
                parent_path = safe_path.parent
                if not self._validate_path(str(parent_path)):
                    return ToolResult(
                        success=False,
                        output="",
                        error=f"Access denied: parent directory {parent_path} is outside the working directory"
                    )
                parent_path.mkdir(parents=True, exist_ok=True)

            safe_path.write_text(content, encoding='utf-8')
            
            return ToolResult(
                success=True,
                output=f"File written successfully: {file_path}",
                data={"file_path": file_path, "size": len(content)}
            )
            
        except Exception as e:
            return ToolResult(success=False, error=str(e))

class FileEditTool(BaseTool):
    """Tool for editing files"""
    
    async def execute(self, file_path: str, old_text: str, new_text: str) -> ToolResult:
        try:
            # Validate path is within working directory
            safe_path = self._safe_path(file_path)
            if safe_path is None:
                return ToolResult(
                    success=False, 
                    output="",
                    error=f"Access denied: {file_path} is outside the working directory"
                )
            
            if not safe_path.exists():
                return ToolResult(success=False, error=f"File not found: {file_path}")
            
            content = safe_path.read_text(encoding='utf-8')
            
            if old_text not in content:
                return ToolResult(
                    success=False,
                    error=f"Text not found in file: {old_text[:50]}..."
                )

            # Request confirmation for file modification
            operation_info = OperationInfo(
                operation_name="Edit File",
                description=f"Modify file: {file_path}",
                risk_level=RiskLevel.LOW,
                affected_items=[file_path],
                context_data={"old_text_length": len(old_text), "new_text_length": len(new_text)}
            )
            if not confirm_operation(operation_info):
                return ToolResult(
                    success=False,
                    output="",
                    error="Operation cancelled by user - file edit not confirmed"
                )

            new_content = content.replace(old_text, new_text)
            safe_path.write_text(new_content, encoding='utf-8')
            
            return ToolResult(
                success=True,
                output=f"File edited successfully: {file_path}",
                data={"file_path": file_path, "changes": 1}
            )
            
        except Exception as e:
            return ToolResult(success=False, error=str(e))

class BashExecuteTool(BaseTool):
    """Tool for executing bash commands"""

    def __init__(self, config: ToolsConfig):
        super().__init__(config)
        self.command_policy = CommandPolicy(config.bash.allowed_commands)

    async def execute(self, command: str, cwd: Optional[str] = None) -> ToolResult:
        try:
            # Validate and set working directory
            if cwd is not None:
                if not self._validate_path(cwd):
                    return ToolResult(
                        success=False,
                        output="",
                        error=f"Access denied: {cwd} is outside the working directory"
                    )
                execution_cwd = str(self._safe_path(cwd))
            else:
                execution_cwd = str(self.working_dir)

            # Parse command safely using CommandPolicy
            try:
                argv = self.command_policy.parse_command_safe(command)
            except ValueError as e:
                return ToolResult(
                    success=False,
                    output="",
                    error=f"Command validation failed: {e}"
                )

            # Check for potentially dangerous commands that need confirmation
            dangerous_patterns = ['rm', 'delete', 'format', 'dd', 'sudo']
            command_lower = command.lower()
            is_dangerous = any(pattern in command_lower for pattern in dangerous_patterns)

            if is_dangerous:
                # Request confirmation for dangerous command
                operation_info = OperationInfo(
                    operation_name="Execute Dangerous Command",
                    description=f"Execute potentially dangerous command: {command}",
                    risk_level=RiskLevel.HIGH,
                    affected_items=[execution_cwd],
                    context_data={"command": command}
                )
                if not confirm_operation(operation_info):
                    return ToolResult(
                        success=False,
                        output="",
                        error="Operation cancelled by user - dangerous command execution not confirmed"
                    )

            # Execute command using secure policy
            result = await self.command_policy.execute_safe(
                argv=argv,
                cwd=execution_cwd,
                timeout=self.config.bash.timeout,
                risk_level="MEDIUM"
            )

            return ToolResult(
                success=result['success'],
                output=result['stdout'],
                error=result['stderr'] if not result['success'] else None
            )

        except Exception as e:
            return ToolResult(
                success=False,
                output="",
                error=f"Command execution failed: {e}"
            )

class GrepSearchTool(BaseTool):
    """Tool for searching in files using grep-like functionality"""
    
    async def execute(self, pattern: str, path: str = ".", 
                     file_pattern: Optional[str] = None,
                     case_sensitive: bool = True) -> ToolResult:
        try:
            # Validate search path is within working directory
            safe_search_path = self._safe_path(path)
            if safe_search_path is None:
                return ToolResult(
                    success=False, 
                    output="",
                    error=f"Access denied: {path} is outside the working directory"
                )
            
            if not safe_search_path.exists():
                return ToolResult(success=False, error=f"Path not found: {path}")
            
            results = []
            
            if safe_search_path.is_file():
                files = [safe_search_path]
            else:
                # Find files matching pattern
                if file_pattern:
                    files = list(safe_search_path.rglob(file_pattern))
                else:
                    files = [f for f in safe_search_path.rglob("*") if f.is_file()]
            
            flags = 0 if case_sensitive else re.IGNORECASE
            regex = re.compile(pattern, flags)
            
            for file_path in files:
                try:
                    # Double-check that each file is within working directory
                    if not self._validate_path(str(file_path)):
                        continue
                    
                    if file_path.suffix in ['.pyc', '.pyo', '.pyd']:
                        continue
                    
                    content = file_path.read_text(encoding='utf-8')
                    lines = content.split('\n')
                    
                    for line_num, line in enumerate(lines, 1):
                        if regex.search(line):
                            results.append({
                                "file": str(file_path),
                                "line": line_num,
                                "content": line.strip()
                            })
                            
                except (UnicodeDecodeError, PermissionError):
                    continue
            
            output = "\n".join([
                f"{r['file']}:{r['line']}:{r['content']}"
                for r in results
            ])
            
            return ToolResult(
                success=True,
                output=output,
                data={"matches": len(results), "results": results}
            )
            
        except Exception as e:
            return ToolResult(success=False, error=str(e))

class GitOperationsTool(BaseTool):
    """Tool for Git operations"""

    def __init__(self, config: ToolsConfig):
        super().__init__(config)
        self.command_policy = CommandPolicy(['git'])

    async def execute(self, operation: str, **kwargs) -> ToolResult:
        try:
            if operation == "status":
                return await self._git_status()
            elif operation == "diff":
                return await self._git_diff(kwargs.get('file'))
            elif operation == "log":
                return await self._git_log(kwargs.get('limit', 10))
            elif operation == "branch":
                return await self._git_branch()
            else:
                return ToolResult(success=False, error=f"Unknown git operation: {operation}")

        except Exception as e:
            return ToolResult(success=False, error=str(e))
    
    async def _git_status(self) -> ToolResult:
        result = await self.command_policy.execute_safe(
            argv=['git', 'status', '--porcelain'],
            timeout=30.0,
            risk_level="LOW"
        )

        return ToolResult(
            success=result['success'],
            output=result['stdout'],
            error=result['stderr'] if not result['success'] else None
        )
    
    async def _git_diff(self, file: Optional[str] = None) -> ToolResult:
        argv = ['git', 'diff']
        if file:
            # Validate file path to prevent injection
            if not self._validate_path(file):
                return ToolResult(success=False, error=f"Invalid file path: {file}")
            argv.append(file)

        result = await self.command_policy.execute_safe(
            argv=argv,
            timeout=30.0,
            risk_level="LOW"
        )

        return ToolResult(
            success=result['success'],
            output=result['stdout'],
            error=result['stderr'] if not result['success'] else None
        )
    
    async def _git_log(self, limit: int = 10) -> ToolResult:
        # Validate limit to prevent injection via format string
        if not isinstance(limit, int) or limit < 1 or limit > 1000:
            return ToolResult(success=False, error=f"Invalid limit: {limit}")

        result = await self.command_policy.execute_safe(
            argv=['git', 'log', '--oneline', '-n', str(limit)],
            timeout=30.0,
            risk_level="LOW"
        )

        return ToolResult(
            success=result['success'],
            output=result['stdout'],
            error=result['stderr'] if not result['success'] else None
        )
    
    async def _git_branch(self) -> ToolResult:
        result = await self.command_policy.execute_safe(
            argv=['git', 'branch'],
            timeout=30.0,
            risk_level="LOW"
        )

        return ToolResult(
            success=result['success'],
            output=result['stdout'],
            error=result['stderr'] if not result['success'] else None
        )

class ToolManager:
    """Manager for all available tools"""
    
    def __init__(self, config: ToolsConfig):
        self.config = config
        self.tools = {
            "file_read": FileReadTool(config),
            "file_write": FileWriteTool(config),
            "file_edit": FileEditTool(config),
            "bash_execute": BashExecuteTool(config),
            "grep_search": GrepSearchTool(config),
            "git_operations": GitOperationsTool(config)
        }
    
    def get_available_tools(self) -> List[str]:
        """Get list of available tools"""
        return [tool for tool in self.tools.keys() if tool in self.config.enabled]
    
    async def execute_tool(self, tool_name: str, **kwargs) -> ToolResult:
        """Execute a tool with given parameters"""
        if tool_name not in self.config.enabled:
            return ToolResult(success=False, error=f"Tool not enabled: {tool_name}")
        
        if tool_name not in self.tools:
            return ToolResult(success=False, error=f"Tool not found: {tool_name}")
        # Argument normalization/safety nets
        try:
            if tool_name == 'file_write':
                # Map 'path' → 'file_path' if provided
                if 'file_path' not in kwargs and 'path' in kwargs:
                    kwargs['file_path'] = kwargs.pop('path')
                # Default content if missing
                if 'content' not in kwargs:
                    kwargs['content'] = ""
        except Exception:
            pass

        tool = self.tools[tool_name]
        return await tool.execute(**kwargs)
    
    def get_tool_description(self, tool_name: str) -> str:
        """Get description of a tool"""
        descriptions = {
            "file_read": "Read contents of a file",
            "file_write": "Write content to a file",
            "file_edit": "Edit a file by replacing text",
            "bash_execute": "Execute bash commands",
            "grep_search": "Search for patterns in files",
            "git_operations": "Perform Git operations"
        }
        return descriptions.get(tool_name, "Unknown tool")
    
    def get_tools_help(self) -> str:
        """Get help text for all available tools"""
        help_text = "Available tools:\n\n"
        for tool_name in self.get_available_tools():
            help_text += f"- {tool_name}: {self.get_tool_description(tool_name)}\n"
        return help_text
